```class Solution {
    public List<Integer> splitIntoFibonacci(String num) {
        List<Integer> res = new ArrayList<>();
        backtrack(num, res, 0);
        return res;
    }

    private boolean backtrack(String num, List<Integer> res, int pos) {
        if (pos == num.length()) {
            return res.size() >= 3;
        }
        long cur = 0;
        while (pos < num.length() && (cur << 1) + cur <= Integer.MAX_VALUE) {
            cur = cur * 10 + num.charAt(pos++) - '0';
            if (cur == 0) {
                res.add(0);
                if (!backtrack(num, res, pos)) {
                    res.remove(res.size() - 1);
                    return false;
                }
                return true;
            }
            if (res.size() >= 2) {
                if ((long) res.get(res.size() - 1) + (long) res.get(res.size() - 2) != cur) {
                    return false;
                }
            }
            res.add((int) cur);
            if (!backtrack(num, res, pos)) {
                res.remove(res.size() - 1);
                return false;
            }
        }
        return false;
    }
}
